  ('social-worker-moex-05130', 'social-worker', 'social-worker-moex-107-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '面對不斷發生之天然災害，社會工作人員在災難管理中占有不可或缺的角色。若將災難管理依其 階段性之工作分類，社會工作者於災難現場提供物資發放、悲傷輔導等服務，這是屬於那一個階 段？', '["災難預防期", "災難整備期", "災難應變期", "災難復原期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "ef1c39f01ce8", "answer_pdf_sha1": "88fc76ce2539", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
